import pathlib

AC_UID = "ac6-mixed-repo-recovery"
AC_TYPE = "data"

CHANGELOG_ANALYST_PATH = pathlib.Path(__file__).parents[3] / "agents" / "changelog-analyst.md"


def test_AC6():
    """
    GIVEN: only nested repo has precommitted content; root repo has normal staged changes
    WHEN:  changelog-analyst runs
    THEN:  root repo gets a normal real commit (non-empty diff); nested repo gets a recovery commit (empty diff with attribution); both push-gate tokens written; commit_status: committed
    """
    text = CHANGELOG_ANALYST_PATH.read_text()

    # Locate the recovery path section
    recovery_idx = text.find("Recovery path when")
    assert recovery_idx != -1, "changelog-analyst.md must contain 'Recovery path when' section"

    recovery_section = text[recovery_idx:]

    # AC6: recovery section must contain BULK=false guard so it is not entered in BULK=true mode
    assert "BULK=false" in recovery_section, (
        "Recovery section must contain 'BULK=false' guard to restrict recovery to non-bulk mode"
    )
